var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"도플갱어 신드롬이군.","JPN":"ドッペルゲンガーシンドロームね。","ENG":"Sounds like the Doppelganger Syndrome.","TWN":"是二重身症候群。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"카운터와 일반인을 가리지 않고, 본체가 살아 있더라도 발생하는 그림자 특이체......","JPN":"カウンター、一般人を問わずに本体が生きていても発生するシャドウ特異体……","ENG":"These unorthodox Shadows are exact copies of humans, Counters or not. And they can be generated even if their original counterparts are alive.","TWN":"不限制裁者或是普通人，即使本體活著，也會發生的暗影特異體……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"녀석들이라면 함선의 동결을 풀기 위해 뭐든 하려 들겠지.","JPN":"連中なら、艦船の凍結を解除するために何でもするはずよ。","ENG":"They'd probably do anything to unlock the stasis.","TWN":"他們會不擇手段地解除艦船的凍結。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"본래 그림자들과 다르게 원본을 흡수해야만 완전해질 수 있으니까.","JPN":"通常のシャドウと違ってオリジナルを吸収しなければ完全になれないのだから。","ENG":"Unlike conventional Shadows, those Doppelgangers have to absorb the original copy to become whole.","TWN":"和原本的暗影不同，他們必須吸收本體才能變得完整。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 내 생각도 같다.","JPN":"ああ。私も同意見だ。","ENG":"That's right. I suspect the same.","TWN":"對，我也是這麼想。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서, 그 뒤엔 어떻게 됐지?","JPN":"それで、その後はどうなったの？","ENG":"So what happened next?","TWN":"所以呢，後來怎麼樣了？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"간신히 놈들의 추격망에서 벗어나 떠돌다가 한 무리의 용병들을 만났지.","JPN":"何とか奴らの追撃を逃れて流れ着いた先で、ある傭兵集団に出会った。","ENG":"I barely lost them and wandered about until I met a group of mercenaries.","TWN":"我好不容易擺脫他們的追擊，後來在流浪的時候遇到了一群傭兵。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARGO_SL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_SL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"처음엔 관리국의 생존자들인 줄 알았는데, 못 보던 장비로 이터니움을 채굴하고 있더군.","JPN":"最初は管理局の生存者たちかと思ったが、\\n見慣れない装備でエタニウムの採掘を行っていてな。","ENG":"At first I thought they were survivors from the Administration, until I saw them mining for Eternium with equipment I had never seen before.","TWN":"一開始我以為他們是管理局的倖存者，結果卻看到他們在用陌生的設備採集永恆之金。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그들의 도움으로 돌아오는 데 성공했다.","JPN":"彼らの協力を得て、帰還することに成功したのだ。","ENG":"They helped me come back here.","TWN":"然後我就在他們的幫助之下，成功返回了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 현실 세계는...... 기억 속의 모습과 많이 달라져 있었어.","JPN":"しかし現実世界は……記憶の中の風景とはすっかり変わっていた。","ENG":"But this Normalside... It's a lot different from how I remembered it.","TWN":"但現實世界……已經遠遠不是我記憶中的樣子了。"},"stage":{"bg":"PROLOGUE_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가 알던 관리국은 사라지고, 이면세계와 카운터의 존재까지 세상에 알려졌다니......","JPN":"私の知る管理局は消え失せ、裏世界とカウンターの存在までも\\n世間に知れ渡るとは……","ENG":"The Administration as I knew it is no more, and even the lay public is aware of the existence of the Counterside and Counters...","TWN":"我所知道的管理局不但消失了，就連異界和制裁者的存在為世人所知。"},"stage":{"bg":"PROLOGUE_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"처음에는 정말 나유빈의 말처럼 다른 세계로 넘어온 줄 알았다.","JPN":"最初はイチノセの言う通り、本当に別世界に来たのかと思ったくらいだ。","ENG":"At first, I thought we had reached a parallel world as Yubin suggested.","TWN":"一開始我還真的以為就像羅瑜斌所說，來到了另一個世界。"},"stage":{"bg":"PROLOGUE_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 조금 더 조사해 보니, 그저 시간이 흘렀을 뿐이었어.","JPN":"しかし調査した結果、ただ時間が経ったにすぎないことがわかった。","ENG":"But when I looked into it a little more, it turns out that time had just passed by.","TWN":"但再稍微調查了一下，才發現只是時間流逝了而已。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"생각보다...... 아주 많이.","JPN":"想定よりも遥かに……長い時間がな。","ENG":"A lot more... than I thought.","TWN":"流逝得……很多。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"내 연락처는 어떻게 안 거지?","JPN":"どうやって私の連絡先を知ったの？","ENG":"How did you find my contact info?","TWN":"妳是怎麼知道我的連絡方式的？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"날 도와 준 용병들이 너희 회사와 같이 일한 적이 있다더군.","JPN":"助けてくれた傭兵たちが、君の会社と仕事を共にしたことがあると言っていた。","ENG":"It turns out the mercenaries who helped me once worked with your company.","TWN":"幫助我的傭兵們說曾經和你們的公司合作過。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이수연이란 이름을 듣고 혹시나 하는 마음에 연락했다.","JPN":"カナミという名前を耳にして、もしやと思い連絡したのだ。","ENG":"I heard them mention your name and reached out just in case.","TWN":"我聽到李秀妍這個名字後，就抱著試試看的心態連絡了妳。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"어차피 다른 사람들은 살았는지 죽었는지도 알 수 없었으니까.","JPN":"他の者たちが生存しているかどうかすらわからなかったからな。","ENG":"Besides, there was no other way to know if the others are alive or not.","TWN":"反正，我也不知道其他人到底是活著，還是死了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇군...... 사정은 이해했어.","JPN":"なるほど……事情は理解したわ。","ENG":"I see... I understand your circumstances now.","TWN":"原來如此……情況我大致都了解了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서 이제 어쩔 셈이야?","JPN":"で、これからどうするの？","ENG":"So what are you going to do about it?","TWN":"那妳接下來打算怎麼做？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"적응을 원한다면 손 닿는 데까지 도와 줄 수 있어.","JPN":"今の世界に適応したいならできる限りの協力はするわ。","ENG":"If you need help acclimating to this new era, I'll help you as much as I can.","TWN":"如果妳想要適應這個世界，我可以在能力所及的範圍幫助妳。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"세상은 아직 네 생각만큼 많이 달라지진 않았거든. 너만큼 강력한 올드 카운터를 원하는 곳은 어디든 있을 거야.","JPN":"生憎、世界はあなたが考えているほど変わっていないの。\\nあなたほどの強力なオールドカウンターが必要とされる場所はまだいくらでもあるはずよ。","ENG":"The world really hasn't changed as much as you'd think. I'm sure there's plenty of folks out there who could use the services of a powerful Counter from the glory days like you.","TWN":"世界的變化沒有妳想像中的那麼大，像妳這樣強大的老制裁者到哪都很受歡迎。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"고마운 제안이군.","JPN":"ありがたい提案だな。","ENG":"I appreciate the offer.","TWN":"謝謝妳的提議。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 내가 널 찾아온 건 다른 부탁이 있어서야.","JPN":"だが、私が君を訪ねたのは別のお願いをするためだ。","ENG":"But I'm really here for another reason.","TWN":"但我會來找妳，是有別的事情想要拜託妳。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"간신히 빠져 나왔지만...... 그곳에는 내 부하들이 남아 있다.","JPN":"かろうじて抜け出すことはできたが……あそこには私の部下たちが残っている。","ENG":"Although I managed to get out just barely, my troops are still back there.","TWN":"我雖然好不容易逃了出來……但我的部下還留在那裡。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"더 늦기 전에 구해내야 해.","JPN":"間に合わなくなる前に救い出さなければ。","ENG":"I must save them before it's too late.","TWN":"我必須在為時已晚之前救出他們才行。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지금 날 도와 줄 사람은 너뿐이다. 이수연.","JPN":"今の私が頼れる人間は君だけだ。カナミ。","ENG":"You're the only one who can help me with this right now, Sooyeon.","TWN":"現在能幫我的人只有妳了，李秀妍。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"나를 도와 주겠나?","JPN":"私を助けてくれるか？","ENG":"Will you help me?","TWN":"妳可以幫幫我嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 녀석도 그렇고, 옛 친구라는 건 항상 귀찮은 일을 끌고 오는 법이군.","JPN":"あいつといい、旧友というものはいつだって\\n面倒事を持ち込んでくれるのね。","ENG":"Why's it always the old friends who bring you the most annoying things to take care of?","TWN":"那傢伙也是這樣，所謂的老朋友總是會帶來麻煩的事情呢。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"말해 두지만 난 예전의 내가 아니야.","JPN":"言っておくけど、今の私はかつての私とは違うわ。","ENG":"Let me make one thing clear. I'm not the same person you once knew.","TWN":"我先說好，我已經不是以前的我了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"감상적인 이유만으로 날뛰던 철부지 꼬맹이는 이제 없다는 뜻이지.","JPN":"感傷的な理由で暴れ回っていた青臭いガキは\\nもうどこにもいないのよ。","ENG":"That rowdy kid who'd get all emotional and passionate isn't here anymore.","TWN":"意思是我已經不是那個感情用事的天真小鬼了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이수연......","JPN":"カナミ……","ENG":"Sooyeon...","TWN":"李秀妍……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 방주에 남은 구 관리국의 유산을 건질 수 있다면 그럭저럭 수지는 맞을 것 같군.","JPN":"まあ、箱舟に残された旧管理局の遺産を\\n拾い上げることができるなら、収支はトントンってところかもしれないわね。","ENG":"But I suppose it'll be worth the effort if we can salvage the Old Administration's legacy in the Ark.","TWN":"不過，如果能得到方舟裡遺留的舊管理局遺產，那倒是很划算。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"추가로 그림자들에게서 얻을 이터니움도 전부 양도하겠다면, 도와 줄게.","JPN":"さらに、シャドウたちから手に入るであろうエタニウムも\\nすべて譲ってくれるなら、力になってあげてもいいわ。","ENG":"If you'd be willing to forfeit all the Eternium from the Shadows as well, I'll help you.","TWN":"再加上從暗影身上獲得的永恆之金，如果妳把那些都讓給我，我就幫妳。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런 조건이라면 얼마든지!","JPN":"そのような条件なら大いに構わん！","ENG":"With pleasure!","TWN":"這樣的條件完全沒問題！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"고맙다. 역시 널 찾아오길 잘했어.","JPN":"感謝する。やはり君を訪ねてきて正解だった。","ENG":"Thank you. I knew I made the right choice seeking you out.","TWN":"謝謝妳，來找妳果然是對的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"내 이익을 위해 도와 주는 거야. 부담스러우니까 너무 기뻐하지 마.","JPN":"あなたを助けるのは自分の利益のためよ。\\nあまり喜ばれるとバツが悪いわ。","ENG":"I'm only doing this because it profits me. Stop being so happy about it. You're making me feel bad.","TWN":"我是為了我的利益才幫妳的，不要那麼高興，妳這樣讓人很有壓力。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"솔직하지 못한 점은 내가 알던 이수연과 똑같군.","JPN":"素直でないところは私の知るカナミと変わらないな。","ENG":"Well, at least you're still dishonest about your feelings like the old days.","TWN":"不夠坦率這一點，依舊是我認識的那個李秀妍。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 미안하지만, 한 가지 부탁이 더 있다.","JPN":"ところで、もし可能ならもう一つ頼みたいことがある。","ENG":"Sorry to trouble you, but I do have one more favor to ask of you.","TWN":"不過有點不好意思，我還有件事情想要拜託妳。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"부하들을 구하려면 함선의 동결을 풀 수 있는 방법이 필요해.","JPN":"部下たちを助けるには艦船の凍結を解除する手立てが必要だ。","ENG":"In order to save the troops, we need a way to undo the cryostasis on the ship.","TWN":"為了救出我的部下，必需要有解除艦船凍結的方法。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"혹시 관리국의 보안 시스템을 다룰 줄 아는 자가 있나?","JPN":"管理局のセキュリティシステムに精通した人間を知らないか？","ENG":"Do you know of anyone who can crack the Administration's security system?","TWN":"妳認不認識會處理管理局安全系統的人？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그거라면 걱정하지 마.","JPN":"そのことなら心配しなくて大丈夫よ。","ENG":"Don't worry about that.","TWN":"這點不用擔心。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마침 이런 일에 딱 맞는 사람이 한 명 있거든.","JPN":"おあつらえ向きの人を一人知っているの。","ENG":"I've got just the right person for that sort of work.","TWN":"正好有一個人很適合這種事。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};